import{_ as a,o,c as l,ag as i}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Cline 配置","description":"","frontmatter":{},"headers":[],"relativePath":"tools/cline.md","filePath":"tools/cline.md"}'),r={name:"tools/cline.md"};function t(d,e,n,s,h,c){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="cline-配置" tabindex="-1">Cline 配置 <a class="header-anchor" href="#cline-配置" aria-label="Permalink to &quot;Cline 配置&quot;">​</a></h1><p>Cline 是一个 VS Code 扩展，提供 AI 编程助手功能。</p><h2 id="这是什么工具" tabindex="-1">这是什么工具 <a class="header-anchor" href="#这是什么工具" aria-label="Permalink to &quot;这是什么工具&quot;">​</a></h2><p>Cline 是一个编辑器插件，需要在 VS Code 中安装和使用。它支持多种 AI Provider，包括 OpenAI Compatible。</p><h2 id="配置前需要准备什么" tabindex="-1">配置前需要准备什么 <a class="header-anchor" href="#配置前需要准备什么" aria-label="Permalink to &quot;配置前需要准备什么&quot;">​</a></h2><ul><li>有效的 API Key</li><li>默认 Base URL：<code>https://api.1010101.asia/</code></li></ul><h2 id="从哪里打开配置入口" tabindex="-1">从哪里打开配置入口 <a class="header-anchor" href="#从哪里打开配置入口" aria-label="Permalink to &quot;从哪里打开配置入口&quot;">​</a></h2><ol><li>打开 VS Code</li><li>点击左侧活动栏的 Cline 图标（齿轮或机器人图标）</li><li>点击右上角的齿轮图标，打开设置面板</li></ol><h2 id="最短完整配置步骤" tabindex="-1">最短完整配置步骤 <a class="header-anchor" href="#最短完整配置步骤" aria-label="Permalink to &quot;最短完整配置步骤&quot;">​</a></h2><ol><li>在 Cline 设置面板中，找到 <code>API Provider</code> 选项</li><li>选择 <code>OpenAI Compatible</code></li><li>在 <code>Base URL</code> 字段中输入：<code>https://api.1010101.asia/</code></li><li>在 <code>API Key</code> 字段中输入你的 API Key</li><li>在 <code>Model</code> 字段中输入模型名（如 <code>gpt-4</code>）</li><li>点击 <code>Verify</code> 或 <code>Save</code></li></ol><h2 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h2><h3 id="设置面板字段" tabindex="-1">设置面板字段 <a class="header-anchor" href="#设置面板字段" aria-label="Permalink to &quot;设置面板字段&quot;">​</a></h3><ul><li><strong>API Provider</strong>: OpenAI Compatible</li><li><strong>Base URL</strong>: <code>https://api.1010101.asia/</code></li><li><strong>API Key</strong>: <code>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code></li><li><strong>Model</strong>: <code>gpt-4</code></li></ul><h2 id="如何验证生效" tabindex="-1">如何验证生效 <a class="header-anchor" href="#如何验证生效" aria-label="Permalink to &quot;如何验证生效&quot;">​</a></h2><ol><li>在 Cline 面板中输入一个简单问题</li><li>点击发送</li><li>如果收到正常回复，说明配置成功</li></ol><p>或：</p><ol><li>在设置面板中点击 <code>Verify</code> 按钮</li><li>如果显示&quot;连接成功&quot;或类似提示，说明配置正确</li></ol><h2 id="常见报错与排查" tabindex="-1">常见报错与排查 <a class="header-anchor" href="#常见报错与排查" aria-label="Permalink to &quot;常见报错与排查&quot;">​</a></h2><h3 id="_401-unauthorized" tabindex="-1">401 Unauthorized <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;401 Unauthorized&quot;">​</a></h3><p><strong>原因</strong>：API Key 错误或无效</p><p><strong>排查</strong>：</p><ul><li>检查 API Key 是否正确</li><li>检查 API Key 是否有多余空格</li><li>确认 API Key 是否已过期或被撤销</li></ul><h3 id="_404-not-found" tabindex="-1">404 Not Found <a class="header-anchor" href="#_404-not-found" aria-label="Permalink to &quot;404 Not Found&quot;">​</a></h3><p><strong>原因</strong>：Base URL 错误</p><p><strong>排查</strong>：</p><ul><li>检查 Base URL 是否正确</li><li>确认 Base URL 以 <code>/</code> 结尾</li><li>检查网络连接是否正常</li></ul><h3 id="模型列表为空" tabindex="-1">模型列表为空 <a class="header-anchor" href="#模型列表为空" aria-label="Permalink to &quot;模型列表为空&quot;">​</a></h3><p><strong>原因</strong>：Base URL 错误或服务商不支持模型列表查询</p><p><strong>排查</strong>：</p><ul><li>检查 Base URL 是否正确</li><li>手动输入模型名（如 <code>gpt-4</code>）</li></ul><h3 id="连接超时" tabindex="-1">连接超时 <a class="header-anchor" href="#连接超时" aria-label="Permalink to &quot;连接超时&quot;">​</a></h3><p><strong>原因</strong>：网络问题或 Base URL 不可达</p><p><strong>排查</strong>：</p><ul><li>检查网络连接</li><li>确认 Base URL 可以访问</li><li>尝试在浏览器中访问 Base URL</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="base-url-格式" tabindex="-1">Base URL 格式 <a class="header-anchor" href="#base-url-格式" aria-label="Permalink to &quot;Base URL 格式&quot;">​</a></h3><p>对于 OpenAI Compatible Provider，Base URL 应该是服务商的端点地址，而不是 OpenAI 的默认地址。</p><h3 id="模型名称" tabindex="-1">模型名称 <a class="header-anchor" href="#模型名称" aria-label="Permalink to &quot;模型名称&quot;">​</a></h3><p>某些服务商可能使用不同的模型名称。请根据服务商文档确认正确的模型名。</p><h3 id="保存设置" tabindex="-1">保存设置 <a class="header-anchor" href="#保存设置" aria-label="Permalink to &quot;保存设置&quot;">​</a></h3><p>修改设置后，确保点击 <code>Save</code> 或 <code>Verify</code> 按钮，否则配置可能不会生效。</p><h3 id="vs-code-重启" tabindex="-1">VS Code 重启 <a class="header-anchor" href="#vs-code-重启" aria-label="Permalink to &quot;VS Code 重启&quot;">​</a></h3><p>某些情况下，修改配置后需要重启 VS Code 才能生效。</p>',43)])])}const x=a(r,[["render",t]]);export{p as __pageData,x as default};
